import logging

def get_logger(name):
    logger = logging.getLogger(name)
    logger.setLevel(logging.INFO)

    if not logger.handlers:
        handler = logging.StreamHandler()
        formatter = logging.Formatter(
            "%(asctime)s - %(name)s - %(levelname)s - %(message)s"
        )
        handler.setFormatter(formatter)
        logger.addHandler(handler)

    return logger
# ===== END utils\logger.py =====

# ===== BEGIN utils\helpers.py =====
import re

def clean_username(raw_username: str) -> str:
    """Removes @ and whitespace from instagram username."""
    if not raw_username:
        return ""
    return raw_username.replace("@", "").strip()

def parse_number(text: str) -> int:
    """
    Parses a string like '1.2M', '10K', '1,500' into an integer.
    """
    if not text:
        return 0
    
    text = text.upper().replace(",", "").replace(" ", "")
    
    multipliers = {'K': 1_000, 'M': 1_000_000, 'B': 1_000_000_000}
    
    for suffix, multiplier in multipliers.items():
        if suffix in text:
            try:
                num = float(text.replace(suffix, ""))
                return int(num * multiplier)
            except ValueError:
                return 0
    
    try:
        return int(float(text))
    except ValueError:
        return 0

def extract_hashtags(text: str) -> list[str]:
    """Extracts hashtags from a given string/caption."""
    if not text:
        return []
    return re.findall(r"#(\w+)", text)

# ===== END utils\helpers.py =====

# ===== BEGIN utils\rate_limiter.py =====
import time
import random

logger = get_logger(__name__)

def sleep_between_requests(min_seconds: float = 2.0, max_seconds: float = 5.0):
    """
    Sleep for a random amount of time between min_seconds and max_seconds
    to avoid rate limiting or being blocked.
    """
    sleep_time = random.uniform(min_seconds, max_seconds)
    logger.debug(f"Sleeping for {sleep_time:.2f} seconds...")
    time.sleep(sleep_time)

def handle_rate_limit(retry_after: int = 60):
    """
    Handle explicit rate limits (e.g., HTTP 429) by sleeping for a longer period.
    """
    logger.warning(f"Rate limited! Sleeping for {retry_after} seconds...")
    time.sleep(retry_after)

# ===== END utils\rate_limiter.py =====

