import psycopg2
from psycopg2.extensions import connection

logger = get_logger(__name__)

def get_db_connection() -> connection:
    """
    Establishes and returns a connection to the PostgreSQL database.
    """
    try:
        conn = psycopg2.connect(
            host=DB_HOST,
            port=DB_PORT,
            dbname=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD
        )
        return conn
    except Exception as e:
        logger.error(f"Failed to connect to database: {e}")
        raise

def init_db():
    """
    Initializes the database schema if it doesn't exist.
    """
    conn = get_db_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS influencers (
                id SERIAL PRIMARY KEY,
                platform VARCHAR(50) NOT NULL,
                username VARCHAR(255) UNIQUE NOT NULL,
                fullname VARCHAR(255),
                followers INT DEFAULT 0,
                bio TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );
        """)
        
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS posts (
                id SERIAL PRIMARY KEY,
                influencer_id INT REFERENCES influencers(id),
                post_url TEXT UNIQUE NOT NULL,
                likes INT DEFAULT 0,
                comments INT DEFAULT 0,
                views INT DEFAULT 0,
                posted_at TIMESTAMP,
                scraped_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );
        """)
        
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS metrics (
                id SERIAL PRIMARY KEY,
                influencer_id INT REFERENCES influencers(id),
                engagement_rate FLOAT DEFAULT 0.0,
                avg_likes INT DEFAULT 0,
                avg_comments INT DEFAULT 0,
                calculated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );
        """)
        
        conn.commit()
        logger.info("Database schema initialized successfully.")
    except Exception as e:
        logger.error(f"Error initializing database: {e}")
        conn.rollback()
        raise
    finally:
        cursor.close()
        conn.close()

# ===== END db\connection.py =====

# ===== BEGIN db\db_writer.py =====

logger = get_logger(__name__)

def save_influencer(influencer_data: dict) -> int:
    """
    Saves or updates an influencer and returns their ID.
    Expects keys: platform, username, fullname, followers, bio
    """
    conn = get_db_connection()
    cursor = conn.cursor()
    influencer_id = 0
    try:
        cursor.execute("""
            INSERT INTO influencers (platform, username, fullname, followers, bio)
            VALUES (%(platform)s, %(username)s, %(fullname)s, %(followers)s, %(bio)s)
            ON CONFLICT (username) 
            DO UPDATE SET 
                fullname = EXCLUDED.fullname,
                followers = EXCLUDED.followers,
                bio = EXCLUDED.bio
            RETURNING id;
        """, influencer_data)
        influencer_id = cursor.fetchone()[0]
        conn.commit()
        logger.info(f"Saved influencer {influencer_data.get('username')} with ID {influencer_id}")
    except Exception as e:
        logger.error(f"Error saving influencer: {e}")
        conn.rollback()
        raise
    finally:
        cursor.close()
        conn.close()
        
    return influencer_id

def save_posts(posts_data: list[dict]):
    """
    Saves a list of posts.
    Expects keys: influencer_id, post_url, likes, comments, views, posted_at
    """
    if not posts_data:
        return
        
    conn = get_db_connection()
    cursor = conn.cursor()
    try:
        for post in posts_data:
            cursor.execute("""
                INSERT INTO posts (influencer_id, post_url, likes, comments, views, posted_at)
                VALUES (%(influencer_id)s, %(post_url)s, %(likes)s, %(comments)s, %(views)s, %(posted_at)s)
                ON CONFLICT (post_url) 
                DO UPDATE SET 
                    likes = EXCLUDED.likes,
                    comments = EXCLUDED.comments,
                    views = EXCLUDED.views,
                    scraped_at = CURRENT_TIMESTAMP;
            """, post)
        conn.commit()
        logger.info(f"Saved {len(posts_data)} posts.")
    except Exception as e:
        logger.error(f"Error saving posts: {e}")
        conn.rollback()
        raise
    finally:
        cursor.close()
        conn.close()

def save_metrics(metrics_data: dict):
    """
    Saves calculated metrics for an influencer.
    Expects keys: influencer_id, engagement_rate, avg_likes, avg_comments
    """
    conn = get_db_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("""
            INSERT INTO metrics (influencer_id, engagement_rate, avg_likes, avg_comments)
            VALUES (%(influencer_id)s, %(engagement_rate)s, %(avg_likes)s, %(avg_comments)s);
        """, metrics_data)
        conn.commit()
        logger.info(f"Saved metrics for influencer ID {metrics_data.get('influencer_id')}")
    except Exception as e:
        logger.error(f"Error saving metrics: {e}")
        conn.rollback()
        raise
    finally:
        cursor.close()
        conn.close()

# ===== END db\db_writer.py =====

# ===== BEGIN pipeline\cleaner.py =====

logger = get_logger(__name__)

def clean_influencer_data(raw_data: dict) -> dict:
    """
    Cleans influencer data (e.g. handles missing bio, null followers)
    """
    cleaned = raw_data.copy()
    
    if not cleaned.get("bio"):
        cleaned["bio"] = ""
        
    followers = cleaned.get("followers")
    if not isinstance(followers, int) or (followers is not None and followers < 0):
        cleaned["followers"] = 0
        
    return cleaned

def clean_posts_data(raw_posts: list[dict]) -> list[dict]:
    """
    Remove duplicates and handle missing values in posts list.
    """
    if not raw_posts:
        return []
        
    # Remove duplicates based on URL
    seen_urls = set()
    cleaned_posts = []
    
    for post in raw_posts:
        url = post.get("post_url")
        if url in seen_urls:
            continue
            
        seen_urls.add(url)
        
        # Ensure numerics are intact
        for key in ["likes", "comments", "views"]:
            val = post.get(key)
            if not isinstance(val, int) or (val is not None and val < 0):
                post[key] = 0
                
        cleaned_posts.append(post)
        
    return cleaned_posts

# ===== END pipeline\cleaner.py =====

# ===== BEGIN pipeline\metrics.py =====

logger = get_logger(__name__)

def calculate_engagement(followers: int, posts: list[dict]) -> dict:
    """
    Calculates avg likes, avg comments, and overall engagement rate.
    Engagement Rate = ((Avg Likes + Avg Comments) / Followers) * 100
    """
    if not posts:
        return {
            "engagement_rate": 0.0,
            "avg_likes": 0,
            "avg_comments": 0
        }
        
    total_likes = sum(p.get("likes", 0) for p in posts)
    total_comments = sum(p.get("comments", 0) for p in posts)
    
    num_posts = len(posts)
    avg_likes = total_likes // num_posts
    avg_comments = total_comments // num_posts
    
    engagement_rate = 0.0
    if followers > 0:
        engagement_rate = ((avg_likes + avg_comments) / followers) * 100.0
        
    return {
        "engagement_rate": float(f"{engagement_rate:.2f}"),
        "avg_likes": avg_likes,
        "avg_comments": avg_comments
    }

# ===== END pipeline\metrics.py =====

# ===== BEGIN pipeline\processor.py =====

logger = get_logger(__name__)

from typing import Optional

def process_and_store_influencer(raw_profile: dict, raw_posts: Optional[list[dict]] = None) -> int:
    """
    Coordinates the pipeline: cleans data, calculates metrics, saves to DB.
    Returns the database ID of the influencer.
    """
    logger.info(f"Processing data for {raw_profile.get('username')}")
    
    # 1. Clean Data
    profile = clean_influencer_data(raw_profile)
    posts = clean_posts_data(raw_posts) if raw_posts else []
    
    # 2. Store Influencer (we need ID for posts/metrics)
    influencer_id = save_influencer(profile)
    
    # 3. Store Posts
    if posts:
        # Add influencer_id to each post
        for post in posts:
            post["influencer_id"] = influencer_id
        save_posts(posts)
        
    # 4. Calculate & Store Metrics
    metrics = calculate_engagement(profile.get("followers", 0), posts)
    metrics["influencer_id"] = influencer_id
    save_metrics(metrics)
    
    logger.info(f"Pipeline complete for {profile.get('username')}")
    return influencer_id

# ===== END pipeline\processor.py =====

# ===== BEGIN instagram\parsers.py =====
import re
from html import unescape


MEDIA_PATH_PATTERN = re.compile(r'href=["\'](/(?:reel|p|tv)/[^"\']+/?)["\']', re.IGNORECASE)
USERNAME_PATH_PATTERN = re.compile(r'href=["\']/([A-Za-z0-9._]+)/?["\']')
FULLNAME_PATTERN = re.compile(r"from\s+(?P<fullname>.+?)\s+\(@(?P<username>[A-Za-z0-9._]+)\)", re.IGNORECASE)
FOLLOWERS_PATTERN = re.compile(r"(?P<followers>[0-9.,KMB]+)\s+Followers", re.IGNORECASE)
LIKES_PATTERN = re.compile(r"(?P<likes>[0-9.,KMB]+)\s+Likes?", re.IGNORECASE)
COMMENTS_PATTERN = re.compile(r"(?P<comments>[0-9.,KMB]+)\s+Comments?", re.IGNORECASE)
VIEWS_PATTERN = re.compile(r"(?P<views>[0-9.,KMB]+)\s+(?:Views?|Plays?)", re.IGNORECASE)

RESERVED_SEGMENTS = {
    "about",
    "accounts",
    "api",
    "challenge",
    "developer",
    "direct",
    "download",
    "explore",
    "graphql",
    "legal",
    "oauth",
    "p",
    "popular",
    "press",
    "reel",
    "reels",
    "stories",
    "tags",
    "tv",
    "web",
}


def normalize_instagram_path(path: str) -> str:
    path = (path or "").strip()
    if not path:
        return ""
    if not path.startswith("/"):
        path = f"/{path}"
    if not path.endswith("/"):
        path = f"{path}/"
    return path


def is_valid_instagram_username(candidate: str) -> bool:
    if not candidate:
        return False

    normalized = candidate.strip().strip("/").lower()
    if normalized in RESERVED_SEGMENTS:
        return False

    return bool(re.fullmatch(r"[A-Za-z0-9._]+", normalized))


def unique_ordered(values: list[str]) -> list[str]:
    seen = set()
    ordered = []

    for value in values:
        if value in seen:
            continue
        seen.add(value)
        ordered.append(value)

    return ordered


def extract_media_paths_from_html(html: str, limit: int | None = None) -> list[str]:
    matches = [normalize_instagram_path(match) for match in MEDIA_PATH_PATTERN.findall(html or "")]
    media_paths = unique_ordered([match for match in matches if match])
    return media_paths[:limit] if limit else media_paths


def extract_candidate_usernames_from_html(html: str, limit: int | None = None) -> list[str]:
    candidates = []

    for candidate in USERNAME_PATH_PATTERN.findall(html or ""):
        if is_valid_instagram_username(candidate):
            candidates.append(candidate.strip("/"))

    usernames = unique_ordered(candidates)
    return usernames[:limit] if limit else usernames


def parse_profile_meta_description(meta_description: str) -> dict:
    description = unescape(meta_description or "")
    parsed = {"fullname": "", "followers": 0}

    fullname_match = FULLNAME_PATTERN.search(description)
    if fullname_match:
        parsed["fullname"] = fullname_match.group("fullname").strip()

    followers_match = FOLLOWERS_PATTERN.search(description)
    if followers_match:
        parsed["followers"] = parse_number(followers_match.group("followers"))

    return parsed


def parse_post_meta_description(meta_description: str) -> dict:
    description = unescape(meta_description or "")
    parsed = {"likes": 0, "comments": 0, "views": 0}

    likes_match = LIKES_PATTERN.search(description)
    if likes_match:
        parsed["likes"] = parse_number(likes_match.group("likes"))

    comments_match = COMMENTS_PATTERN.search(description)
    if comments_match:
        parsed["comments"] = parse_number(comments_match.group("comments"))

    views_match = VIEWS_PATTERN.search(description)
    if views_match:
        parsed["views"] = parse_number(views_match.group("views"))

    return parsed

# ===== END instagram\parsers.py =====

