from pathlib import Path

from playwright.sync_api import Browser, BrowserContext, Page, Playwright, TimeoutError as PlaywrightTimeoutError

logger = get_logger(__name__)

INSTAGRAM_USER_AGENT = (
    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
    "AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36"
)
INSTAGRAM_VIEWPORT = {"width": 1280, "height": 800}
PROJECT_ROOT = Path(__file__).resolve().parent
SESSION_FILE_PATH = Path(INSTAGRAM_SESSION_FILE)
if not SESSION_FILE_PATH.is_absolute():
    SESSION_FILE_PATH = PROJECT_ROOT / SESSION_FILE_PATH


def launch_instagram_context(playwright: Playwright) -> tuple[Browser, BrowserContext, Page]:
    launch_options = {"headless": HEADLESS_MODE}
    if PROXY_URL:
        launch_options["proxy"] = {"server": PROXY_URL}

    browser = playwright.chromium.launch(**launch_options)

    context_options = {
        "user_agent": INSTAGRAM_USER_AGENT,
        "viewport": INSTAGRAM_VIEWPORT,
    }
    if SESSION_FILE_PATH.exists():
        context_options["storage_state"] = str(SESSION_FILE_PATH)

    context = browser.new_context(**context_options)
    page = context.new_page()
    return browser, context, page


def go_to_instagram_url(page: Page, context: BrowserContext, url: str) -> None:
    page.goto(url, wait_until="domcontentloaded", timeout=60000)

    if is_login_page(page):
        if not login_to_instagram(page, context):
            logger.warning("Instagram login was required but could not be completed.")
            return

        page.goto(url, wait_until="domcontentloaded", timeout=60000)


def is_login_page(page: Page) -> bool:
    return page.locator("input[name='username']").count() > 0 and page.locator("input[name='password']").count() > 0


def login_to_instagram(page: Page, context: BrowserContext) -> bool:
    if not INSTAGRAM_USERNAME or not INSTAGRAM_PASSWORD:
        logger.warning("Instagram credentials are not configured. Continuing without login.")
        return False

    logger.info("Attempting Instagram login to reuse an authenticated session.")

    try:
        if not is_login_page(page):
            page.goto("https://www.instagram.com/accounts/login/", wait_until="domcontentloaded", timeout=60000)

        dismiss_cookie_prompt(page)

        page.locator("input[name='username']").fill(INSTAGRAM_USERNAME)
        page.locator("input[name='password']").fill(INSTAGRAM_PASSWORD)
        page.locator("button[type='submit']").click()

        page.wait_for_timeout(4000)
        dismiss_optional_prompt(page)
        dismiss_optional_prompt(page)

        if is_login_page(page):
            logger.error("Instagram login appears to have failed. Check credentials or checkpoint prompts.")
            return False

        SESSION_FILE_PATH.parent.mkdir(parents=True, exist_ok=True)
        context.storage_state(path=str(SESSION_FILE_PATH))
        logger.info("Saved Instagram session state for future runs.")
        return True
    except PlaywrightTimeoutError:
        logger.error("Timed out during Instagram login.")
        return False
    except Exception as exc:
        logger.error(f"Instagram login failed: {exc}")
        return False


def dismiss_cookie_prompt(page: Page) -> None:
    button_names = [
        "Allow all cookies",
        "Allow essential and optional cookies",
        "Only allow essential cookies",
    ]

    for name in button_names:
        try:
            button = page.get_by_role("button", name=name)
            if button.count() > 0:
                button.first.click()
                page.wait_for_timeout(1000)
                return
        except Exception:
            continue


def dismiss_optional_prompt(page: Page) -> None:
    for name in ["Not Now", "Cancel"]:
        try:
            button = page.get_by_role("button", name=name)
            if button.count() > 0:
                button.first.click()
                page.wait_for_timeout(1000)
                return
        except Exception:
            continue

# ===== END instagram\session.py =====

# ===== BEGIN instagram\hashtag_scraper.py =====
from playwright.sync_api import sync_playwright


logger = get_logger(__name__)


def _extract_username_from_media_page(page) -> str:
    for anchor in page.query_selector_all("header a[href]"):
        href = anchor.get_attribute("href") or ""
        parts = [part for part in href.split("/") if part]
        if not parts:
            continue

        candidate = parts[0]
        if candidate not in {"p", "reel", "reels", "explore"}:
            return str(candidate)

    usernames = extract_candidate_usernames_from_html(page.content(), limit=1)
    return str(usernames[0]) if usernames else ""


def get_usernames_from_hashtag(hashtag: str, max_users: int = 10) -> list[str]:
    """Scrape a hashtag page and return the usernames shown in the reel/post grid."""
    usernames = []
    url = f"https://www.instagram.com/explore/tags/{hashtag}/"
    logger.info(f"Scraping hashtag: #{hashtag} for up to {max_users} users")

    with sync_playwright() as p:
        browser, context, page = launch_instagram_context(p)

        try:
            go_to_instagram_url(page, context, url)
            sleep_between_requests(4, 6)

            media_paths = []
            for _ in range(8):
                html = page.content()
                usernames = extract_candidate_usernames_from_html(html, limit=max_users)
                media_paths = extract_media_paths_from_html(html, limit=max_users * 2)

                if len(usernames) >= max_users or len(media_paths) >= max_users:
                    break

                page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
                sleep_between_requests(2, 4)

            logger.info(
                f"Discovered {len(usernames)} candidate usernames and {len(media_paths)} media links for #{hashtag}"
            )

            if len(usernames) < max_users:
                fallback_usernames = list(usernames)
                for media_path in media_paths:
                    if len(fallback_usernames) >= max_users:
                        break

                    try:
                        go_to_instagram_url(page, context, f"https://www.instagram.com{media_path}")
                        sleep_between_requests(2, 4)
                        username = _extract_username_from_media_page(page)
                        if username and username not in fallback_usernames:
                            fallback_usernames.append(username)
                    except Exception as exc:
                        logger.warning(f"Error extracting username from {media_path}: {exc}")

                usernames = fallback_usernames

            logger.info(f"Collected {len(usernames)} usernames from #{hashtag}")
        except Exception as exc:
            logger.error(f"Failed to scrape hashtag {hashtag}: {exc}")
            logger.warning("Instagram might be blocking the request or requiring login.")
        finally:
            browser.close()

    return [u for i, u in enumerate(usernames) if i < max_users]

# ===== END instagram\hashtag_scraper.py =====

