import re

from playwright.sync_api import sync_playwright


logger = get_logger(__name__)


def _get_meta_description(page) -> str:
    selectors = ['meta[property="og:description"]', 'meta[name="description"]']
    for selector in selectors:
        locator = page.locator(selector)
        if locator.count() > 0:
            content = locator.first.get_attribute("content")
            if content:
                return content
    return ""


def _extract_bio(page, username: str) -> str:
    selectors = [
        "header section",
        "main header",
    ]

    for selector in selectors:
        try:
            element = page.query_selector(selector)
            if not element:
                continue

            lines = [line.strip() for line in element.inner_text().splitlines() if line.strip()]
            filtered = []
            for line in lines:
                lower_line = line.lower()
                if username.lower() in lower_line:
                    continue
                if any(token in lower_line for token in ["followers", "following", "posts", "message"]):
                    continue
                filtered.append(line)

            if filtered:
                return " ".join([f for i, f in enumerate(filtered) if i < 3])
        except Exception:
            continue

    return ""


def get_profile_data(username: str) -> dict:
    """Scrapes profile metadata like followers, bio, fullname."""
    url = f"https://www.instagram.com/{username}/"
    logger.info(f"Scraping profile: {username}")

    data = {"platform": "instagram", "username": username, "fullname": "", "followers": 0, "bio": ""}

    with sync_playwright() as p:
        browser, context, page = launch_instagram_context(p)
        try:
            go_to_instagram_url(page, context, url)
            sleep_between_requests(3, 5)

            title = page.title()
            title_match = re.search(r"^(.*?)\s*\(@", title)
            if title_match:
                data["fullname"] = title_match.group(1).strip()

            meta_desc = _get_meta_description(page)
            parsed_meta = parse_profile_meta_description(meta_desc)
            if parsed_meta["fullname"] and not data["fullname"]:
                data["fullname"] = parsed_meta["fullname"]
            data["followers"] = parsed_meta["followers"]
            data["bio"] = _extract_bio(page, username)

            logger.info(f"Successfully scraped profile {username} (Followers: {data['followers']})")
        except Exception as exc:
            logger.error(f"Failed to scrape profile {username}: {exc}")
        finally:
            browser.close()

    return data

# ===== END instagram\profile_scraper.py =====

# ===== BEGIN instagram\post_scraper.py =====
from typing import Optional

from playwright.sync_api import sync_playwright


logger = get_logger(__name__)


def _get_meta_description(page) -> str:
    selectors = ['meta[property="og:description"]', 'meta[name="description"]']
    for selector in selectors:
        locator = page.locator(selector)
        if locator.count() > 0:
            content = locator.first.get_attribute("content")
            if content:
                return content
    return ""


def get_recent_posts(username: str, limit: Optional[int] = None) -> list[dict]:
    """Scrapes the most recent posts for an Instagram user including extracted likes/comments."""
    if limit is None:
        limit = SCRAPING_LIMITS.get("INSTAGRAM_POSTS", 12)

    url = f"https://www.instagram.com/{username}/"
    logger.info(f"Scraping up to {limit} posts for {username}")

    posts = []
    with sync_playwright() as p:
        browser, context, page = launch_instagram_context(p)
        try:
            go_to_instagram_url(page, context, url)
            sleep_between_requests(3, 5)

            post_hrefs = []
            for _ in range(8):
                current_paths = extract_media_paths_from_html(page.content())
                for path in current_paths:
                    if path not in post_hrefs:
                        post_hrefs.append(path)

                if len(post_hrefs) >= limit:
                    break

                page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
                sleep_between_requests(2, 4)

            limited_hrefs = [h for i, h in enumerate(post_hrefs) if i < limit]
            logger.info(f"Found {len(limited_hrefs)} media links. Extracting stats...")

            for href in limited_hrefs:
                post_url = f"https://www.instagram.com{href}"
                try:
                    go_to_instagram_url(page, context, post_url)
                    sleep_between_requests(2, 4)

                    parsed_meta = parse_post_meta_description(_get_meta_description(page))
                    time_locator = page.locator("time")
                    posted_at = None
                    if time_locator.count() > 0:
                        posted_at = time_locator.first.get_attribute("datetime")
                except Exception as exc:
                    logger.warning(f"Could not extract stats for {post_url}: {exc}")
                    parsed_meta = {"likes": 0, "comments": 0, "views": 0}
                    posted_at = None

                posts.append({
                    "post_url": post_url,
                    "likes": parsed_meta["likes"],
                    "comments": parsed_meta["comments"],
                    "views": parsed_meta["views"],
                    "posted_at": posted_at,
                })

            logger.info(f"Collected and parsed {len(posts)} posts for {username}")
        except Exception as exc:
            logger.error(f"Failed to scrape posts for {username}: {exc}")
        finally:
            browser.close()

    return posts

# ===== END instagram\post_scraper.py =====

