from googleapiclient.discovery import build

logger = get_logger(__name__)


def find_channels_by_keyword(keyword: str, max_results: int = 3) -> list[str]:
    """Search YouTube for a keyword and return a list of Channel IDs."""
    logger.info(f"Searching YouTube channels for keyword: '{keyword}'")

    if not YOUTUBE_API_KEY:
        logger.error("No YouTube API key found. Skipping YouTube channel search.")
        return []

    try:
        youtube = build("youtube", "v3", developerKey=YOUTUBE_API_KEY)
        request = youtube.search().list(
            q=keyword,
            part="id",
            type="channel",
            maxResults=max_results,
            regionCode="IN",
        )
        response = request.execute()

        channel_ids = []
        for item in response.get("items", []):
            channel_id = item.get("id", {}).get("channelId")
            if channel_id:
                channel_ids.append(channel_id)

        logger.info(f"Found {len(channel_ids)} channels for '{keyword}'")
        return channel_ids
    except Exception as exc:
        logger.error(f"YouTube search API failed: {exc}")
        return []

# ===== END youtube\channel_finder.py =====

# ===== BEGIN youtube\channel_scraper.py =====
from googleapiclient.discovery import build

logger = get_logger(__name__)


def get_channel_info(channel_id: str) -> dict:
    """Retrieve channel metadata (subscribers, views, name) using YouTube API."""
    logger.info(f"Scraping channel info for {channel_id}")

    data = {
        "platform": "youtube",
        "username": channel_id,
        "fullname": "",
        "followers": 0,
        "bio": "",
    }

    if not YOUTUBE_API_KEY:
        logger.error(f"No YouTube API key. Skipping channel lookup for {channel_id}.")
        return data

    try:
        youtube = build("youtube", "v3", developerKey=YOUTUBE_API_KEY)
        request = youtube.channels().list(
            part="snippet,statistics",
            id=channel_id,
        )
        response = request.execute()

        items = response.get("items", [])
        if items:
            channel = items[0]
            snippet = channel.get("snippet", {})
            stats = channel.get("statistics", {})

            data["fullname"] = snippet.get("title", "")
            data["bio"] = snippet.get("description", "")
            data["followers"] = int(stats.get("subscriberCount", 0))

            logger.info(f"Successfully scraped channel {data['fullname']} ({data['followers']} subs)")
        else:
            logger.warning(f"Channel {channel_id} not found.")
    except Exception as exc:
        logger.error(f"YouTube Channels API failed for {channel_id}: {exc}")

    return data

# ===== END youtube\channel_scraper.py =====

# ===== BEGIN youtube\video_scraper.py =====
from typing import Optional
from googleapiclient.discovery import build

logger = get_logger(__name__)


def get_recent_videos(channel_id: str, limit: Optional[int] = None) -> list[dict]:
    """Retrieve recent video stats (views, likes, comments) via YouTube API."""
    if limit is None:
        limit = SCRAPING_LIMITS.get("YOUTUBE_VIDEOS", 5)

    logger.info(f"Scraping up to {limit} recent videos for {channel_id}")

    videos = []

    if not YOUTUBE_API_KEY:
        logger.error(f"No YouTube API key. Skipping recent video lookup for {channel_id}.")
        return videos

    try:
        youtube = build("youtube", "v3", developerKey=YOUTUBE_API_KEY)

        search_req = youtube.search().list(
            part="id",
            channelId=channel_id,
            maxResults=limit,
            order="date",
            type="video",
        )
        search_resp = search_req.execute()

        video_ids = [item["id"]["videoId"] for item in search_resp.get("items", []) if "videoId" in item.get("id", {})]

        if not video_ids:
            logger.info(f"No videos found for channel {channel_id}")
            return videos

        videos_req = youtube.videos().list(
            part="snippet,statistics",
            id=",".join(video_ids),
        )
        videos_resp = videos_req.execute()

        for item in videos_resp.get("items", []):
            vid_id = item["id"]
            stats = item.get("statistics", {})
            snippet = item.get("snippet", {})

            videos.append({
                "post_url": f"https://www.youtube.com/watch?v={vid_id}",
                "likes": int(stats.get("likeCount", 0)),
                "comments": int(stats.get("commentCount", 0)),
                "views": int(stats.get("viewCount", 0)),
                "posted_at": snippet.get("publishedAt", None),
            })

        logger.info(f"Successfully scraped {len(videos)} videos for {channel_id}")
    except Exception as exc:
        logger.error(f"YouTube Videos API failed for {channel_id}: {exc}")

    return videos

# ===== END youtube\video_scraper.py =====

# ===== BEGIN main.py =====
import sys


logger = get_logger(__name__)


def run_instagram_scraper():
    """Run the core Instagram scraping pipeline."""

    for hashtag in INSTAGRAM_HASHTAGS:
        logger.info(f"--- Starting Instagram pipeline for hashtag: #{hashtag} ---")
        limit = SCRAPING_LIMITS.get("INSTAGRAM_USERS_PER_HASHTAG", 50)
        usernames = get_usernames_from_hashtag(hashtag, max_users=limit)

        if not usernames:
            logger.warning(f"No Instagram usernames found for #{hashtag}")
            continue

        for username in usernames:
            try:
                profile_data = get_profile_data(username)
                posts_data = get_recent_posts(username)
                process_and_store_influencer(profile_data, posts_data)
            except Exception as exc:
                logger.error(f"Failed to process Instagram user {username}: {exc}")


def run_youtube_scraper():
    """Run the secondary YouTube scraping pipeline."""
    for keyword in YOUTUBE_KEYWORDS:
        logger.info(f"--- Starting YouTube pipeline for keyword: '{keyword}' ---")
        channel_ids = find_channels_by_keyword(keyword, max_results=YOUTUBE_SEARCH_RESULTS)

        if not channel_ids:
            logger.warning(f"No YouTube channels found for '{keyword}'")
            continue

        for channel_id in channel_ids:
            try:
                channel_data = get_channel_info(channel_id)
                video_data = get_recent_videos(channel_id)
                process_and_store_influencer(channel_data, video_data)
            except Exception as exc:
                logger.error(f"Failed to process YouTube channel {channel_id}: {exc}")


def main():
    logger.info("Initializing Influencer Scraper MVP")

    try:
        init_db()
    except Exception as exc:
        logger.error(f"Could not initialize database: {exc}")
        logger.error("Please check database credentials or ensure PostgreSQL is running.")
        sys.exit(1)

    if not ENABLE_INSTAGRAM and not ENABLE_YOUTUBE:
        logger.warning("Both scraping pipelines are disabled. Enable at least one platform in the environment.")
        return

    if ENABLE_INSTAGRAM:
        run_instagram_scraper()

    if ENABLE_YOUTUBE:
        run_youtube_scraper()

    logger.info("Scraping run completed successfully.")


if __name__ == "__main__":
    main()

# ===== END main.py =====
